def first_missing_positive(nums):
    n = len(nums)
    freq = {}
    for num in nums:
        if num < 0:
            continue
        if num in freq:
            freq[num] += 1
        else:
            freq[num] = 1
    for i in range(1, n + 1):
        if i not in freq:
            return i
